func employeeStatusLabel(status models.EmployeeStatus) string {
	switch status {
	case models.EmployeeStatusActive:
		return "Active"
	case models.EmployeeStatusInactive:
		return "Inactive"
	case models.EmployeeStatusTerminated:
		return "Terminated"
	default:
		return string(status)
	}
}

func employeeMemberTypeLabel(memberType models.EmployeeMemberType) string {
	switch memberType {
	case models.EmployeeMemberEmployee:
		return "Employee"
	case models.EmployeeMemberContractor:
		return "Contractor"
	case models.EmployeeMemberConstructionContractor:
		return "Construction Contractor"
	default:
		return string(memberType)
	}
}

func payFrequencyLabel(frequency models.PayFrequency) string {
	for _, option := range payFrequencyOptions() {
		if option.Value == string(frequency) {
			return option.Label
		}
	}
	return string(frequency)
}

func employeeStatusBadgeClass(status models.EmployeeStatus) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch status {
	case models.EmployeeStatusActive:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.EmployeeStatusTerminated:
		return base + "bg-background text-text-muted2 border border-border line-through"
	default:
		return base + "bg-warning-soft text-warning border border-warning-soft"
	}
}

func payrollRunTitle(run models.PayrollRun) string {
	if run.RunNumber != "" {
		return run.RunNumber
	}
	return "Run " + Uitoa(run.ID)
}

func payrollRunStatusLabel(status models.PayrollRunStatus) string {
	switch status {
	case models.PayrollRunDraft:
		return "Draft"
	case models.PayrollRunCalculated:
		return "Calculated"
	case models.PayrollRunFinalized:
		return "Finalized"
	case models.PayrollRunVoided:
		return "Voided"
	default:
		return string(status)
	}
}

func payrollRunStatusBadgeClass(status models.PayrollRunStatus) string {
	base := "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch status {
	case models.PayrollRunCalculated:
		return base + "bg-primary-soft text-primary border border-primary-soft"
	case models.PayrollRunFinalized:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.PayrollRunVoided:
		return base + "bg-background text-text-muted2 border border-border line-through"
	default:
		return base + "bg-warning-soft text-warning border border-warning-soft"
	}
}

func payrollRunCanCalculate(status models.PayrollRunStatus) bool {
	return status == models.PayrollRunDraft || status == models.PayrollRunCalculated
}

func payrollRunCanFinalize(status models.PayrollRunStatus) bool {
	return status == models.PayrollRunCalculated
}

func payrollRunCanCreateCheques(status models.PayrollRunStatus) bool {
	return status == models.PayrollRunFinalized
}

func payrollRunCanPost(status models.PayrollRunStatus) bool {
	return status == models.PayrollRunFinalized
}

